226xy|function loadAgents(): AgentInfo[] {
227if|	const agents: AgentInfo[] = [];
228kt|	try {
229mm|		const entries = fs.readdirSync(AGENTS_DIR).filter(f => f.endsWith(".md")).sort();
230cc|		for (const entry of entries) {
231el|			const filePath = path.join(AGENTS_DIR, entry);
232dz|			const content = fs.readFileSync(filePath, "utf-8");
233io|			const fmMatch = content.match(/^---\n([\s\S]*?)\n---/);
234vy|			if (!fmMatch) continue;
235al|			const fm = fmMatch[1];
236pz|			let name = "", description = "", model = "";
237jl|			for (const line of fm.split("\n")) {
238qp|				const nm = line.match(/^name:\s*(.+)$/);
239pd|				if (nm) name = nm[1].trim();
240mv|				const dm = line.match(/^description:\s*["']?(.+?)["']?\s*$/);
241mv|				if (dm) description = dm[1].trim();
242aq|				const mm = line.match(/^model:\s*(.+)$/);
243zg|				if (mm) model = mm[1].trim();
244th|			}
245uj|			if (!name) continue;
246rg|			const category = name.split("-")[0];
247vl|			agents.push({ name, description, category, model, filePath });
