// Extract each team's agents list
const teams = [];
let pos = 0;
while (true) {
  const idx = src.indexOf('id: \"', pos);
  if (idx === -1) break;
  const idEnd = src.indexOf('\"', idx + 5);
  const id = src.slice(idx + 5, idEnd);

  // Find agents array after this id
  const agentsIdx = src.indexOf('agents: [', idEnd);
  const agentsEnd = src.indexOf('],', agentsIdx);
  const agentsStr = src.slice(agentsIdx + 8, agentsEnd + 1);
  const agents = [...agentsStr.matchAll(/\"([^\"]+)\"/g)].map(m => m[1]);

  teams.push({ id, agentCount: agents.length });
  pos = agentsEnd;
}

// Verify key teams
const check = (id, expected) => {
  const t = teams.find(t => t.id === id);
  if (!t) { console.log('MISSING:', id); return; }
  if (t.agentCount !== expected) {
    console.log('MISMATCH:', id, 'has', t.agentCount, 'expected', expected);
  } else {
    console.log('OK:', id, t.agentCount);
  }
};

